import React from 'react';
import { Text as CarbonText } from '@carbon/react';

const Text = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonText
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonText>
    );
};

Text.defaultProps = {
    className: ''
};

export default Text;
